const input = $input.first().json;
const body = input.body ?? input;
const job = body.job ?? {};
const eventId = body.event?.id ?? body.eventId;
const jobId = job.id ?? body.jobId;
const callbackUrl = body.callbackUrl;
const callbackSecret = body.callbackSecret;
const selectedIdea = (job.ideas ?? []).find((idea) => idea.id === (job.selectedIdeaId ?? body.selectedIdeaId)) ?? (job.ideas ?? [])[0] ?? null;
if (!jobId || !eventId || !callbackUrl) {
  return [];
}
const seedKeyword = job.seedKeyword ?? body.seedKeyword ?? 'Untitled topic';
const client = job.client ?? body.client ?? 'Unknown client';
const title = selectedIdea?.title ?? seedKeyword;
const angle = selectedIdea?.angle ?? 'Research the topic from a practical SEO angle';
const relatedKeywords = selectedIdea?.relatedKeywords ?? [];
const apiKey = $env.TAVILY_API_KEY;

async function tavilySearch(query, country) {
  if (!apiKey) {
    return { answer: '', results: [] };
  }

  const response = await fetch('https://api.tavily.com/search', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      query,
      topic: 'general',
      search_depth: 'advanced',
      max_results: 4,
      include_answer: 'advanced',
      include_raw_content: 'text',
      country
    })
  });

  if (!response.ok) {
    throw new Error(`Tavily search failed with status ${response.status}`);
  }

  return response.json();
}

function toInsight(result, fallback) {
  const raw = String(result.raw_content ?? result.content ?? fallback ?? '').replace(/\s+/g, ' ').trim();
  return raw.slice(0, 320) || fallback;
}

let thSearch;
let globalSearch;
let searchError = null;

try {
  thSearch = await tavilySearch(`${title} ${seedKeyword} วิธีดูแล อาการ สาเหตุ ข้อควรระวัง`, 'thailand');
  globalSearch = await tavilySearch(`${title} ${seedKeyword} symptoms causes care best practices`, 'united states');
} catch (error) {
  searchError = error instanceof Error ? error.message : 'Unknown Tavily error';
  thSearch = { answer: '', results: [] };
  globalSearch = { answer: '', results: [] };
}

const thResults = Array.isArray(thSearch.results) ? thSearch.results : [];
const globalResults = Array.isArray(globalSearch.results) ? globalSearch.results : [];
const thAnswer = typeof thSearch.answer === 'string' ? thSearch.answer : '';
const globalAnswer = typeof globalSearch.answer === 'string' ? globalSearch.answer : '';

const sources = [
  ...thResults.slice(0, 4).map((result) => ({
    region: 'TH',
    title: result.title || `${title} Thai source`,
    source: result.url || result.favicon || 'Thai search result',
    insight: toInsight(result, `Thai search result related to ${title}`)
  })),
  ...globalResults.slice(0, 4).map((result) => ({
    region: 'Global',
    title: result.title || `${title} global source`,
    source: result.url || result.favicon || 'Global search result',
    insight: toInsight(result, `Global search result related to ${title}`)
  }))
];

const fallbackSources = [
  { region: 'TH', title: `${title} in Thai search context`, source: 'Thai search synthesis', insight: `Use the angle "${angle}" and connect it to Thai wording and decision factors.` },
  { region: 'Global', title: `${title} global best-practice baseline`, source: 'International search synthesis', insight: 'Use global sources to strengthen factual framing, terminology, and reader trust.' }
];

const objective = searchError
  ? `Research pack fallback for "${title}" because Tavily was unavailable.`
  : `Build a Thai and Global research pack for "${title}" for client ${client}.`;

const audience = `Readers searching for ${seedKeyword} who need practical guidance, trustworthy context, and a clear next step.`;

const gaps = [
  `Need a Thai-first explanation for ${title} that still cites global terminology where useful.`,
  `Competitors often skip side-by-side comparison between local phrasing and international best practices.`,
  `Content should cover related keywords such as ${relatedKeywords.join(', ') || 'supporting long-tail phrases'} and convert them into FAQ and internal links.`
];

const summaryHooks = [thAnswer, globalAnswer].filter(Boolean).join(' ');
const callbackPayload = {
  eventId,
  jobId,
  type: 'research',
  status: 'succeeded',
  workflowRunId: $execution.id,
  message: 'Research workflow completed in n8n poller.',
  stage: 'researching',
  payload: {
    provider: searchError ? 'n8n-poller-fallback' : 'tavily',
    executionId: $execution.id,
    error: searchError,
    summaryHooks
  },
  research: {
    objective,
    audience,
    gaps,
    sources: sources.length > 0 ? sources : fallbackSources
  }
};

const callbackResponse = await fetch(callbackUrl, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    ...(callbackSecret ? { 'x-callback-secret': callbackSecret } : {})
  },
  body: JSON.stringify(callbackPayload)
});

if (!callbackResponse.ok) {
  throw new Error(`Research callback failed with status ${callbackResponse.status}`);
}

return [];
